module RefModule(
    input wire [1:0] in,
    output wire out0,
    output wire out1,
    output wire out2,
    output wire out3
    );

  wire _n01 = in[0] ^ 2'b00[0];
  wire _n02 = in[1] ^ 2'b00[1];
  wire _n03 = in[2] ^ 2'b00[2];
  wire _n04 = in[3] ^ 2'b00[3];
  assign out0 = ~_n01 & ~_n02 & ~_n03 & ~_n04;
assign out1 = (in == 2'b01);
assign out2 = (in == 2'b10);
assign out3 = (in == 2'b11);

endmodule
